import React, { useRef, useState, useEffect } from 'react';
import { useNavigate, Link, useLocation } from 'react-router-dom';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  // Helper to check if a path is active
  const isActive = (path) => location.pathname === path;

  // Common nav link style
  const navLinkBase = {
    textDecoration: 'none',
    color: '#0078d4',
    fontSize: '0.95rem',
    fontWeight: 600,
    display: 'flex',
    alignItems: 'center',
    padding: '8px 16px',
    borderRadius: '20px',
    transition: 'all 0.3s',
    background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
    marginRight: '10px',
    boxShadow: '0 2px 8px #0078d411',
    border: '1px solid #e0e6ed',
  };
  const navLinkActive = {
    background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
    color: '#fff',
    boxShadow: '0 2px 8px #d6000044',
    border: '1.5px solid #0078d4',
  };

  // Dropdown state for profile menu
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Add a ref to the profile button to match dropdown width
  const profileBtnRef = useRef(null);
  const [profileBtnWidth, setProfileBtnWidth] = useState(0);
  useEffect(() => {
    if (profileBtnRef.current) {
      setProfileBtnWidth(profileBtnRef.current.offsetWidth);
    }
  }, [dropdownOpen, userInfo?.Username]);

  // Close dropdown on outside click
  useEffect(() => {
    if (!dropdownOpen) return;
    function handleClick(e) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [dropdownOpen]);

  // Keyboard accessibility (ESC to close)
  useEffect(() => {
    if (!dropdownOpen) return;
    function handleKey(e) {
      if (e.key === 'Escape') setDropdownOpen(false);
    }
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [dropdownOpen]);

  // Add login time extraction and storage
  useEffect(() => {
    let loginTime = localStorage.getItem('loginTime');
    if (!loginTime) {
      // Try to get from token
      try {
        const token = localStorage.getItem('token');
        if (token) {
          const tokenData = JSON.parse(atob(token.split('.')[1]));
          if (tokenData.iat) {
            // iat is in seconds
            loginTime = new Date(tokenData.iat * 1000).toLocaleString();
          }
        }
      } catch {}
      if (!loginTime) {
        loginTime = new Date().toLocaleString();
      }
      localStorage.setItem('loginTime', loginTime);
    }
  }, []);
  const loginTime = localStorage.getItem('loginTime') || '';

  return (
    <header style={{
      background: 'linear-gradient(90deg, #fff 0%, #fafdff 60%, #e3f0ff 90%, #fbeaec 100%)',
      boxShadow: '0 2px 10px rgba(0, 120, 212, 0.07)',
      borderBottom: '1.5px solid #e0e6ed',
      fontFamily: 'Poppins, Inter, sans-serif',
      fontWeight: 500,
      letterSpacing: 0.1,
      zIndex: 100,
      padding: '1.2rem 2.2rem'
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <Link to="/dashboard">
              <img 
                src="/Logo/Sparkle RFID svg.svg" 
                alt="Sparkle RFID" 
                style={{ 
                  height: '48px',
                  marginRight: '30px'
                }} 
              />
            </Link>
            <nav className="d-flex align-items-center">
              <Link 
                to="/dashboard"
                style={{
                  ...navLinkBase,
                  ...(isActive('/dashboard') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/dashboard')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-home me-2" style={{ color: isActive('/dashboard') ? '#fff' : '#0078d4' }}></i>
                Home
              </Link>
              <Link 
                to="/rfid-integration"
                style={{
                  ...navLinkBase,
                  marginLeft: '10px',
                  ...(isActive('/rfid-integration') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/rfid-integration')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-plug me-2" style={{ color: isActive('/rfid-integration') ? '#fff' : '#0078d4' }}></i>
                RFID Integration
              </Link>
              <Link 
                to="/inventory"
                style={{
                  ...navLinkBase,
                  marginLeft: '10px',
                  ...(isActive('/inventory') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/inventory')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-box me-2" style={{ color: isActive('/inventory') ? '#fff' : '#0078d4' }}></i>
                Inventory
              </Link>
              <Link 
                to="/upload-rfid"
                style={{
                  ...navLinkBase,
                  marginLeft: '10px',
                  ...(isActive('/upload-rfid') ? navLinkActive : {}),
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                  const icon = e.currentTarget.querySelector('i');
                  if (icon) icon.style.color = '#fff';
                }}
                onMouseOut={e => {
                  if (isActive('/upload-rfid')) {
                    e.currentTarget.style.background = navLinkActive.background;
                    e.currentTarget.style.color = navLinkActive.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#fff';
                  } else {
                    e.currentTarget.style.background = navLinkBase.background;
                    e.currentTarget.style.color = navLinkBase.color;
                    const icon = e.currentTarget.querySelector('i');
                    if (icon) icon.style.color = '#0078d4';
                  }
                }}
              >
                <i className="fas fa-upload me-2" style={{ color: isActive('/upload-rfid') ? '#fff' : '#0078d4' }}></i>
                Upload EPC Data
              </Link>
            </nav>
          </div>
          {userInfo && (
            <div className="d-flex align-items-center" style={{ position: 'relative' }}>
              {/* Profile button */}
              <button
                ref={profileBtnRef}
                className="profile-btn"
                style={{
                  background: dropdownOpen
                    ? 'linear-gradient(90deg, #fafdff 0%, #e3f0ff 100%)'
                    : 'linear-gradient(90deg, #fafdff 0%, #f7fafd 100%)',
                  padding: '10px 22px 10px 16px',
                  borderRadius: '26px',
                  display: 'flex',
                  alignItems: 'center',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontWeight: 600,
                  boxShadow: dropdownOpen
                    ? '0 4px 18px #0078d422, 0 1.5px 6px #0001'
                    : '0 2px 8px #0078d411',
                  border: dropdownOpen ? '2px solid #0078d4' : '1.5px solid #e0e6ed',
                  color: '#222',
                  fontSize: '1.08rem',
                  cursor: 'pointer',
                  outline: 'none',
                  transition: 'box-shadow 0.2s, background 0.2s, border 0.2s',
                  position: 'relative',
                  zIndex: 11,
                  minWidth: 170,
                }}
                onClick={() => setDropdownOpen((v) => !v)}
                aria-haspopup="true"
                aria-expanded={dropdownOpen}
                tabIndex={0}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #e3f0ff 0%, #b3d8ff 100%)';
                  e.currentTarget.style.boxShadow = '0 4px 18px #0078d422, 0 1.5px 6px #0001';
                  e.currentTarget.style.border = '2px solid #0078d4';
                }}
                onMouseOut={e => {
                  if (!dropdownOpen) {
                    e.currentTarget.style.background = 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)';
                    e.currentTarget.style.boxShadow = '0 2px 8px #0078d411';
                    e.currentTarget.style.border = '1.5px solid #e0e6ed';
                  }
                }}
              >
                <span style={{
                  background: 'linear-gradient(135deg, #b3d8ff 0%, #0078d4 100%)',
                  borderRadius: '50%',
                  padding: 7,
                  marginRight: 10,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  boxShadow: '0 2px 8px #0078d411',
                }}>
                  <i className="fas fa-user" style={{ color: '#fff', fontSize: 18 }}></i>
                </span>
                <span style={{ fontWeight: 700, color: '#222', fontFamily: 'Poppins, Inter, sans-serif', fontSize: '1.08rem', letterSpacing: 0.1 }}>
                  {userInfo.Username}
                </span>
                <i className={`fas fa-chevron-${dropdownOpen ? 'up' : 'down'} ms-2`} style={{ color: '#0078d4', fontSize: 15, marginLeft: 12 }}></i>
              </button>
              {/* Dropdown menu */}
              {dropdownOpen && (
                <div
                  ref={dropdownRef}
                  className="profile-dropdown"
                  style={{
                    position: 'absolute',
                    top: 'calc(100% + 8px)',
                    right: 0,
                    minWidth: profileBtnWidth || 170,
                    maxWidth: profileBtnWidth || 320,
                    width: profileBtnWidth || 'auto',
                    background: 'linear-gradient(135deg, #fff 0%, #f8f9fa 100%)',
                    borderRadius: 14, // sharper look
                    boxShadow: '0 8px 32px #0078d422',
                    padding: '8px 0 4px 0',
                    zIndex: 100,
                    border: '1.5px solid #e0e6ed',
                    animation: 'fadeInDown 0.18s',
                    backdropFilter: 'blur(8px)',
                    WebkitBackdropFilter: 'blur(8px)',
                  }}
                  tabIndex={-1}
                >
                  {/* Login Time */}
                  <div style={{ padding: '6px 18px', display: 'flex', alignItems: 'center', gap: 10, whiteSpace: 'nowrap' }}>
                    <span style={{
                      background: 'linear-gradient(135deg, #0078d4 0%, #b3d8ff 100%)',
                      borderRadius: '50%',
                      padding: 6,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      boxShadow: '0 2px 8px #0078d411',
                    }}>
                      <i className="fas fa-clock" style={{ color: '#fff', fontSize: 15 }}></i>
                    </span>
                    <span style={{ color: '#0078d4', fontWeight: 700, fontSize: 14 }}>Login Time:</span>
                    <span style={{ color: '#222', fontWeight: 600, fontSize: 14, marginLeft: 4, overflow: 'hidden', textOverflow: 'ellipsis' }}>{loginTime}</span>
                  </div>
                  {/* Client Code */}
                  <div style={{ padding: '6px 18px', display: 'flex', alignItems: 'center', gap: 10, whiteSpace: 'nowrap' }}>
                    <span style={{
                      background: 'linear-gradient(135deg, #0078d4 0%, #b3d8ff 100%)',
                      borderRadius: '50%',
                      padding: 6,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      boxShadow: '0 2px 8px #0078d411',
                    }}>
                      <i className="fas fa-id-badge" style={{ color: '#fff', fontSize: 15 }}></i>
                    </span>
                    <span style={{ color: '#0078d4', fontWeight: 700, fontSize: 14 }}>Client Code:</span>
                    <span style={{ color: '#d60000', fontWeight: 800, fontSize: 14, marginLeft: 4 }}>{userInfo.ClientCode}</span>
                  </div>
                  <hr style={{ margin: '6px 0 6px 0', border: 0, borderTop: '1px solid #e0e6ed' }} />
                  {/* Logout */}
                  <button
                    onClick={handleLogout}
                    style={{
                      background: 'none',
                      border: 'none',
                      color: '#0078d4',
                      fontWeight: 700,
                      fontFamily: 'Poppins, Inter, sans-serif',
                      fontSize: 15,
                      width: '100%',
                      textAlign: 'left',
                      padding: '8px 18px',
                      display: 'flex',
                      alignItems: 'center',
                      gap: 10,
                      cursor: 'pointer',
                      borderRadius: 10,
                      transition: 'background 0.18s, color 0.18s',
                    }}
                    onMouseOver={e => { e.currentTarget.style.background = 'rgba(214,0,0,0.10)'; e.currentTarget.style.color = '#d60000'; }}
                    onMouseOut={e => { e.currentTarget.style.background = 'none'; e.currentTarget.style.color = '#0078d4'; }}
                  >
                    <span style={{
                      background: 'linear-gradient(135deg, #d60000 0%, #ff6161 100%)',
                      borderRadius: '50%',
                      padding: 6,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      marginRight: 6,
                    }}>
                      <i className="fas fa-sign-out-alt" style={{ color: '#fff', fontSize: 15 }}></i>
                    </span>
                    Logout
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;
